// webtorrent-peer-help.min.js — Гуманная P2P помощь сети для RobinHood P2P
// Версия 1.0.2
(function(){
'use strict';
if(!window.RTCPeerConnection&&!window.webkitRTCPeerConnection)return;
var PEER_HELP_VERSION='1.0.2';
var ANNOUNCE_INTERVAL=300000;
var PEER_TTL=900000;
var TRACKER_URL='https://robincall.stephanclaps-491.workers.dev/announce';
var active=false,peerId=null,announceTimer=null,isAnnouncing=false;

async function announceToTracker(pid){
    if(isAnnouncing)return;
    isAnnouncing=true;
    try{
        var url=TRACKER_URL+'?peer_id='+encodeURIComponent(pid)+'&event=started';
        var resp=await fetch(url,{method:'GET',signal:AbortSignal.timeout(5000)});
        if(resp.ok){
            var data=await resp.json();
            console.log('[PeerHelp] Анонс. Пиров в сети:',data.complete||0);
        }
    }catch(e){}
    isAnnouncing=false;
}

async function stopAnnounce(pid){
    try{
        var url=TRACKER_URL+'?peer_id='+encodeURIComponent(pid)+'&event=stopped';
        await fetch(url,{method:'GET',signal:AbortSignal.timeout(3000)});
    }catch(e){}
}

window.RobinHoodPeerHelp={
    start:function(pid){
        if(active)return;
        if(!pid)return;
        peerId=pid;
        active=true;
        console.log('[PeerHelp] Запущен. Трафик: ~2-5 КБ/час');
        announceToTracker(peerId);
        announceTimer=setInterval(function(){
            if(document.hidden)return;
            announceToTracker(peerId);
        },ANNOUNCE_INTERVAL);
        try{localStorage.setItem('robinhood_peer_help_active','true')}catch(e){}
    },
    stop:function(){
        if(!active)return;
        active=false;
        if(announceTimer){clearInterval(announceTimer);announceTimer=null}
        if(peerId)stopAnnounce(peerId);
        try{localStorage.setItem('robinhood_peer_help_active','false')}catch(e){}
        console.log('[PeerHelp] Остановлен');
    },
    isActive:function(){return active},
    getStats:function(){return{active:active,peerId:peerId}}
};
try{var wasActive=localStorage.getItem('robinhood_peer_help_active')==='true';if(wasActive)console.log('[PeerHelp] Ожидает peerId')}catch(e){}
console.log('[PeerHelp] v'+PEER_HELP_VERSION+' загружен');
})();
